// ---- Extension function on String ----
fun String.isEmail(): Boolean {
    return this.contains("@") && this.contains(".")
}

fun String.toTitleCase(): String {
    return this.split(" ").joinToString(" ") { word ->
        word.lowercase().replaceFirstChar { it.uppercase() }
    }
}

// ---- Extension function with receiver ----
fun String.repeat(times: Int): String {
    return this.repeat(times)
}

// ---- Extension function on Int ----
fun Int.isEven(): Boolean {
    return this % 2 == 0
}

fun Int.isPrime(): Boolean {
    if (this < 2) return false
    for (i in 2 until this) {
        if (this % i == 0) return false
    }
    return true
}

// ---- Extension function on List ----
fun <T> List<T>.second(): T? {
    return if (this.size >= 2) this[1] else null
}

fun <T> List<T>.safeGet(index: Int): T? {
    return if (index in this.indices) this[index] else null
}

// ---- Extension function with generic receiver ----
fun <T> T.printInfo(): T {
    println("Value: $this")
    return this
}

// ---- Extension property ----
val String.wordCount: Int
    get() = this.split(Regex("\\s+")).size

val Int.square: Int
    get() = this * this

// ---- Extension function on data class ----
data class User(val name: String, val age: Int)

fun User.greet(): String {
    return "Hello, ${this.name}! You are ${this.age} years old."
}

fun User.isAdult(): Boolean {
    return this.age >= 18
}

// ---- Extension function with nullable receiver ----
fun String?.safeLength(): Int {
    return this?.length ?: 0
}

fun main() {
    // ---- String extensions ----
    val email = "test@example.com"
    println("Is email? ${email.isEmail()}")

    val title = "hello world from kotlin"
    println("Title case: ${title.toTitleCase()}")

    println("Repeat: ${"ha".repeat(3)}")

    // ---- Int extensions ----
    val num = 7
    println("Is 7 even? ${num.isEven()}")
    println("Is 7 prime? ${num.isPrime()}")
    println("Is 4 prime? ${4.isPrime()}")

    // ---- List extensions ----
    val list = listOf(1, 2, 3, 4, 5)
    println("Second element: ${list.second()}")
    println("Element at index 10: ${list.safeGet(10)}")

    // ---- Generic extension ----
    val result = 42.printInfo()
    println("Result: $result")

    // ---- Extension properties ----
    println("Word count: 'Hello world from Kotlin'.wordCount = ${title.wordCount}")
    println("Square of 5: ${5.square}")

    // ---- Data class extensions ----
    val user = User("Alice", 25)
    println(user.greet())
    println("Is adult? ${user.isAdult()}")

    // ---- Nullable extension ----
    val text: String? = null
    println("Safe length: ${text.safeLength()}")
    val nonNullText = "Hello"
    println("Safe length: ${nonNullText.safeLength()}")
}

